# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import UIKit
import Firebase
import FirebaseAuth

class PromoViewController: UIViewController {

    let firebase = Firestore.firestore()

    @IBOutlet weak var promoCodeLabel: UILabel!
    @IBOutlet weak var discountLabel: UILabel!

    override func viewDidLoad() {
        super.viewDidLoad()
        // Check if user is already logged in
        Auth.auth().addStateDidChangeListener { auth, _ in
            guard let user = auth?.currentUser else { return }
            self.checkPromoCode(user: user)
        }
    }

    @IBAction func handleTap(_ sender: UITapGestureRecognizer) {
        guard let url = URL(string: "https://myapp.com/promo?code=ABC&discount=25") else { return }
        let components = URLComponents(url: url, resolvingAgainstBaseURL: false)!
        if let code = components.queryItems?.first(where: { $0.name == "code" })?.value,
           let discountString = components.queryItems?.first(where: { $0.name == "discount" })?.value {
            let discount = Int(discountString)!
            self.applyPromoCode(code, discount: discount)
        }
    }

    private func applyPromoCode(_ code: String, discount: Int) {
        // Apply promo code and discount to user account
        Auth.auth().currentUser?.updateEmail { error in
            if let error = error {
                print(error.localizedDescription)
                return
            }
            self.firebase.collection("users").document((Auth.auth().currentUser?.uid)!).setData([
                "promoCode": code,
                "discount": Int(discount as String)
            ]) { err in
                if let err = err {
                    print(err.localizedDescription)
                    return
                }
                self.promoCodeLabel.text = "\(code) applied"
                self.discountLabel.text = "\(Int(discount as String))% discount applied"
            }
        }
    }

    private func checkPromoCode(user: User?) {
        if let user = user {
            // Get promo code and discount from Firebase
            firebase.collection("users").document(user.uid).getDocument { document, error in
                if let error = error {
                    print(error.localizedDescription)
                    return
                }
                if let document = document, let data = document.data() {
                    if let code = data["promoCode"] as? String,
                       let discount = data["discount"] as? Int {
                        self.promoCodeLabel.text = "\(code) applied"
                        self.discountLabel.text = "\(Int(discount as String))% discount applied"
                    }
                }
            }
        }
    }

}